mapper.sql:
/* wms-outbound-pkcnfrm-sql-oracle.xml - selectPkIstedSql - 피킹확정 - 피킹지시 정보 조회 SQL */ SELECT 0 AS CHK /*체크박스*/ , OBHD.CTKEY /*센터코드*/ , OBHD.OWKEY /*화주사코드*/ , OBHD.OBHDKEY /*출고공통코드(릴리즈코드)*/ , OBHD.OBORDKEY /*출고주문번호(오더코드)*/ , OBHD.ORHDKEY /*S/O 주문번호*/ , OBHD.EXTERNORDERKEY /*고객주문번호*/ , PIHD.PIHDKEY /*피킹헤더코드*/ , OBHD.OBHDDAY /*출고예정일자*/ , OBHD.OBHDTYPECD /*출고헤더유형코드*/ , PIHD.PKWKSTATUSCD /*피킹작업상태코드*/ , OBHD.OBSTATUSCD /*출고상태코드*/ , PIHD.INSERTURKEY /*피킹지시자*/ , PIHD.INSERTDATE /*피킹지시일시*/ , PIHD.PKDIVCD /*피킹 구분 코드*/ , CT.CTNM /*센터명*/ , TOCT.CTKEY AS TOCTKEY /*TO센터코드*/ , TOCT.CTNM AS TOCTNM /*TO센터명*/ FROM TWORK_INFO_OB_HD OBHD /*출고공통정보*/ INNER JOIN TWORK_INFO_PI_HD PIHD /*피킹헤더정보*/ ON OBHD.CTKEY = PIHD.CTKEY AND OBHD.OWKEY = PIHD.OWKEY AND OBHD.PIHDKEY = PIHD.PIHDKEY INNER JOIN TWORK_MST_CT CT /*센터마스터*/ ON OBHD.CTKEY = CT.CTKEY LEFT OUTER JOIN TWORK_MST_CT TOCT /*센터마스터*/ ON OBHD.TOCTKEY = TOCT.CTKEY LEFT OUTER JOIN TWORK_INFO_WA_DT WADT /*웨이브상세*/ ON OBHD.CTKEY = WADT.CTKEY AND OBHD.OWKEY = WADT.OWKEY AND OBHD.OBHDKEY = WADT.OBHDKEY WHERE OBHD.OBSTATUSCD IN ('20','25','30') /*20:피킹지시,25:부분피킹,30:피킹확정 */ AND PIHD.PKDIVCD = '10' /*피킹구분코드 10:오더별피킹*/ AND WADT.WAHDKEY IS NULL
AND #{SEARCH_CONDITION}
GROUP BY OBHD.CTKEY /*센터코드*/ , OBHD.OWKEY /*화주사코드*/ , OBHD.OBHDKEY /*출고공통코드(릴리즈코드)*/ , OBHD.OBORDKEY /*출고주문번호(오더코드)*/ , OBHD.ORHDKEY /*S/O 주문번호*/ , OBHD.EXTERNORDERKEY /*고객주문번호*/ , PIHD.PIHDKEY /*피킹헤더코드*/ , OBHD.OBHDDAY /*출고예정일자*/ , OBHD.OBHDTYPECD /*출고헤더유형코드*/ , PIHD.PKWKSTATUSCD /*피킹작업상태코드*/ , OBHD.OBSTATUSCD /*출고상태코드*/ , PIHD.INSERTURKEY /*피킹지시자*/ , PIHD.INSERTDATE /*피킹지시일시*/ , PIHD.PKDIVCD /*피킹 구분 코드*/ , CT.CTNM /*센터명*/ , TOCT.CTKEY /*TO센터코드*/ , TOCT.CTNM /*TO센터명*/ ORDER BY OBHD.OBHDKEY

