/* wms-outbound-pkcnfrm-sql-oracle.xml - pkHdWkStatusCk - 피킹확정 - 피킹지시정보의 작업상태 체크 */
SELECT PKWKSTATUSCD /*피킹작업상태코드*/
  FROM TWORK_INFO_PI_HD /*피킹헤더정보*/
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}

mapper.update:
/* wms-outbound-pkcnfrm-sql-oracle.xml - updatePkIstCnlObDt - WMS > 출고 관리 > 피킹확정 > 피킹지시 취소 - 릴리즈 상세 상태값 및 수량 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET PKISTQTY = 0
	 , OBDTSTATUSCD = '10'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTSTATUSCD = '20'

/* wms-outbound-pkcnfrm-sql-oracle.xml - updatePkIstCnlObHd - WMS > 출고 관리 > 피킹확정 > 피킹지시 취소 - 릴리즈 헤더 피킹헤더코드 NULL 업데이트 */
UPDATE TWORK_INFO_OB_HD
   SET PIHDKEY = NULL
	 , PKOBHDKEY = NULL
	 , OBWKDATE = NULL
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

/* wms-outbound-pkcnfrm-sql-oracle.xml - updatePkIstCnlAlDt - WMS > 출고 관리 > 피킹확정 > 피킹지시 취소 - 할당 피킹헤더코드 및 피킹상세코드 NULL 업데이트 */
UPDATE TWORK_INFO_AL_DT
   SET PIHDKEY = NULL
     , PIDTKEY = NULL
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}

mapper.delete:
/* wms-outbound-pkcnfrm-sql-oracle.xml - deletePkIstCnlPiDt - WMS > 출고 관리 > 피킹확정 > 피킹지시 취소 - 피킹 상세 삭제 */
DELETE FROM TWORK_INFO_PI_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}

/* wms-outbound-pkcnfrm-sql-oracle.xml - deletePkIstCnlPiHd - WMS > 출고 관리 > 피킹확정 > 피킹지시 취소 - 피킹 헤더 삭제 */
DELETE FROM TWORK_INFO_PI_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}

/* wms-outbound-pkcnfrm-sql-oracle.xml - deletePkIstCnlPiTotDt - WMS > 출고 관리 > 피킹확정 > 피킹지시 취소 - 총량(통합)일경우 총량 삭제 */
DELETE FROM TWORK_INFO_PI_TOT_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}

/* wms-outbound-pkcnfrm-sql-oracle.xml - deletePkIstCnlPiIntgDt - WMS > 출고 관리 > 피킹확정 > 피킹지시 취소 - 총량(통합)일경우 통합 삭제 */
DELETE FROM TWORK_INFO_PI_INTG_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}

mapper.update:
/* wms-outbound-pkcnfrm-sql-oracle.xml - updatePkIstCnlWaHd - WMS > 출고 관리 > 피킹확정 > 피킹지시 취소 - 웨이브 헤더 피킹헤더코드 NULL 업데이트 */
UPDATE TWORK_INFO_WA_HD
   SET PIHDKEY = NULL
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}

mapper.select:
/* wms-outbound-pkcnfrm-sql-oracle.xml - pkObHdStatusSelect - 피킹확정 - 릴리즈코드의 출고헤더상태 조회 */
SELECT OBSTATUSCD /*출고상태코드*/
  FROM TWORK_INFO_OB_HD /*출고공통정보*/
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

/* wms-outbound-pkcnfrm-sql-oracle.xml - pkObDtStatusSelect - 피킹확정 - 릴리즈상세의 출고상세 상태 조회 */
SELECT OBDTSTATUSCD /*출고상세상태코드*/
  FROM TWORK_INFO_OB_DT /*출고상세정보*/
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}

/* wms-outbound-pkcnfrm-sql-oracle.xml - pkDtCnfrmCnlTgtCk - 피킹확정 - 피킹상세번호 확정취소처리 대상 카운트 */
SELECT COUNT(1)
  FROM TWORK_INFO_PI_DT /*피킹상세정보*/
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}
   AND PIDTKEY = #{pidtkey}
   AND PKDTWKSTATUSCD = '10' /*10:피킹확정*/
